export interface PixCopyPasteInput {
  pixKey: string
  amount: number
  description: string
}

function onlyAsciiUpper(value: string): string {
  return value
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toUpperCase()
}

function digits(value: number): string {
  return value.toString().padStart(2, '0')
}

function emvField(id: string, value: string): string {
  return `${id}${digits(value.length)}${value}`
}

function crc16Ccitt(payload: string): string {
  let crc = 0xffff
  for (let i = 0; i < payload.length; i += 1) {
    crc ^= payload.charCodeAt(i) << 8
    for (let j = 0; j < 8; j += 1) {
      if ((crc & 0x8000) !== 0) crc = (crc << 1) ^ 0x1021
      else crc <<= 1
      crc &= 0xffff
    }
  }
  return crc.toString(16).toUpperCase().padStart(4, '0')
}

export function generatePixCopyPaste({ pixKey, amount, description }: PixCopyPasteInput): string {
  const key = pixKey.trim()
  if (!key) throw new Error('pixKey is required')
  if (!Number.isFinite(amount) || amount <= 0) throw new Error('amount must be greater than zero')

  const amountValue = amount.toFixed(2)
  const merchantName = onlyAsciiUpper('DIVIDE AI').slice(0, 25)
  const merchantCity = onlyAsciiUpper('SAO PAULO').slice(0, 15)
  const txid = onlyAsciiUpper(description || 'PAGAMENTO').replace(/[^A-Z0-9]/g, '').slice(0, 25) || 'PAGAMENTO'
  const pixDescription = onlyAsciiUpper(description || 'PAGAMENTO').slice(0, 72)

  const merchantAccountInfo =
    emvField('00', 'br.gov.bcb.pix') +
    emvField('01', key) +
    (pixDescription ? emvField('02', pixDescription) : '')

  const payloadWithoutCrc =
    emvField('00', '01') +
    emvField('26', merchantAccountInfo) +
    emvField('52', '0000') +
    emvField('53', '986') +
    emvField('54', amountValue) +
    emvField('58', 'BR') +
    emvField('59', merchantName) +
    emvField('60', merchantCity) +
    emvField('62', emvField('05', txid)) +
    '6304'

  const crc = crc16Ccitt(payloadWithoutCrc)
  return `${payloadWithoutCrc}${crc}`
}

export function buildPixChargeMessage(params: {
  groupName: string
  amount: number
  pixCode: string
}): string {
  const amountLabel = params.amount.toFixed(2).replace('.', ',')
  return [
    'Ola! ??',
    '',
    `Voce possui um pagamento pendente do grupo "${params.groupName}".`,
    '',
    `Valor: R$ ${amountLabel}`,
    '',
    'Para pagar via PIX, copie e cole o codigo abaixo no seu banco:',
    '',
    params.pixCode,
    '',
    'Apos o pagamento, o sistema atualizara automaticamente.',
    '',
    'Obrigado!',
  ].join('\n')
}
